```typescript
const input = fs.readFileSync(0, "utf8").trim();

function tokenize(): string[] {
  const result: string[] = [];
  let i = 0;
  while (i < input.length) {
    const c = input[i];
    if (/\s/.test(c)) {
      i++;
      continue;
    }
    if (/[+-*/]/.test(c)) {
      result.push(c);
      i++;
    } else if (/[0-9]/.test(c)) {
      let num = "";
      while (i < input.length && /[0-9]/.test(input[i])) {
        num += input[i];
        i++;
      }
      result.push(num);
    } else {
      i++;
    }
  }
  return result;
}

const tokens = tokenize();

function parse(): number {
  let i = 0;

  function peek(): string | null {
    if (i < tokens.length) return tokens[i];
    return null;
  }

  function consume(): string {
    if (i < tokens.length) return tokens[i++];
    return "";
  }

  function parseUnary(): number {
    const op = peek();
    if (op === "+" || op === "-") {
      consume();
      return op === "+" ? parseUnary() : -parseUnary();
    }
    if (op === "*") {
      consume();
      return parseUnary();
    }
    return parseBinary();
  }

  function parseBinary(): number {
    let lhs = parseUnary();
    while (true) {
      const op = peek();
      if (op === "+" || op === "-") {
        consume();
        const rhs = parseUnary();
        lhs = op === "+" ? lhs + rhs : lhs - rhs;
      } else if (op === "*" || op === "/") {
        consume();
        const rhs = parseUnary();
        lhs = op === "*" ? lhs * rhs : Math.trunc(lhs / rhs);
      } else {
        break;
      }
    }
    return lhs;
  }

  return parseBinary();
}

console.log(parse());
